$sec = ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force
$cred = New-Object PSCredential ('usr1cv8', $sec)
$opt = New-PSSessionOption -SkipCACheck -SkipCNCheck -SkipRevocationCheck
$s = New-PSSession -ComputerName 26.100.144.211 -Credential $cred -Authentication Negotiate -SessionOption $opt
Invoke-Command -Session $s -ScriptBlock {
  schtasks /Query /TN StartKassa211 /V /FO LIST 2>&1 | Select-String 'Task To Run|Logon Mode|Run As|Status|Trigger|Schedule'
  $exe='C:\PROGRA~2\MOYSKL~1\CC57~1.EXE'
  & C:\Users\Public\PsExec.exe -accepteula -i 1 -d -u usr1cv8 -p usr1cv8 $exe 2>&1 | Out-String
  $samples=@()
  1..18 | ForEach-Object {
    Start-Sleep 5
    $p = Get-CimInstance Win32_Process | Where-Object {
      $_.Name -match 'moysklad|electron|CC57|kassa|Retail' -or $_.CommandLine -match 'moysklad|MOYSKL'
    } | Select-Object Name,ProcessId,SessionId,@{n='Cmd';e={$_.CommandLine}}
    $samples += [pscustomobject]@{t=$_; count=@($p).Count; names=($p|ForEach-Object Name) -join ','}
  }
  $log='C:\Users\usr1cv8\AppData\Roaming\moysklad-kassa\app.log.2026-07-07'
  $lw=(Get-Item $log).LastWriteTime
  $tail=Get-Content $log -Tail 5
  Get-ChildItem 'C:\Users\usr1cv8\AppData\Roaming\moysklad-kassa\Crashpad\reports' -ErrorAction SilentlyContinue | Sort LastWriteTime -Desc | Select -First 3 Name,LastWriteTime,Length
  [pscustomobject]@{Samples=$samples; LogLastWrite=$lw; LogTail=$tail}
} | ConvertTo-Json -Depth 6
Remove-PSSession $s

$sec = ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force
$cred = New-Object PSCredential ('usr1cv8', $sec)
$opt = New-PSSessionOption -SkipCACheck -SkipCNCheck -SkipRevocationCheck
$s = New-PSSession -ComputerName 26.100.144.211 -Credential $cred -Authentication Negotiate -SessionOption $opt -ErrorAction Stop
Invoke-Command -Session $s -ScriptBlock {
  $p = Get-CimInstance Win32_Process | Where-Object { $_.CommandLine -match 'MOYSKL|moysklad' -or $_.Name -match 'CC57|kassa' }
  $s1 = @($p | Where-Object SessionId -eq 1).Count
  $total = @($p).Count
  $log = 'C:\Users\usr1cv8\AppData\Roaming\moysklad-kassa\app.log.2026-07-07'
  $lw = if (Test-Path $log) { (Get-Item $log).LastWriteTime.ToString('yyyy-MM-dd HH:mm:ss') } else { 'missing' }
  "$total procs ($s1 in session 1) | log mtime $lw"
}
Remove-PSSession $s
